def process_csv(filename):
    import csv

    data = {}
    with open(filename, 'r') as file:
        reader = csv.DictReader(file)
        for row in reader:
            name = row['name']
            score = float(row['score'])
            grade = row['grade']

            if grade == 'A':
                if name not in data['a_students']:
                    data['a_students'].append(name)

            average_score = sum(float(score) for score in data.get('scores', [])) / len(data.get('scores', []))
            data['scores'].append(score)

    return {
        'average_score': average_score,
        'a_students': sorted(set(data.get('a_students', [])))
    }

def two_sum(nums, target):
    num_dict = {}
    for i, num in enumerate(nums):
        complement = target - num
        if complement in num_dict:
            return [num_dict[complement], i]
        num_dict[num] = i
    return []

#!/usr/bin/perl

use strict;
use warnings;

my $filename = $ARGV[0];

open my $fh, '<', $filename or die "Cannot open file '$filename': $!";

my ($total_lines, $error_lines) = (0, 0);

while (my $line = <$fh>) {
    chomp $line;
    $line =~ /\b(error|ERROR)\b/i and $error_lines++;
    $total_lines++;
}

close $fh;

print "$total_lines\n$error_lines\n";

using UnityEngine;

public class FirstPersonController : MonoBehaviour
{
    public float moveSpeed = 5f;
    public float mouseSensitivity = 2f;
    public float jumpForce = 10f;
    public float gravity = -9.81f;

    private Vector3 velocity;
    private Quaternion originalRotation;

    void Update()
    {
        float horizontalMove = Input.GetAxis("Horizontal") * moveSpeed;
        float verticalMove = Input.GetAxis("Vertical") * moveSpeed;

        transform.Translate(horizontalMove, 0f, verticalMove);

        if (Input.GetButton("Jump"))
        {
            velocity.y = jumpForce;
        }

        velocity.y += gravity * Time.deltaTime;

        transform.Translate(0f, 0f, velocity.y * Time.deltaTime);

        originalRotation = transform.rotation;
        float mouseX = Input.GetAxis("Mouse X") * mouseSensitivity;
        float mouseY = Input.GetAxis("Mouse Y") * mouseSensitivity;

        transform.Rotate(mouseX, mouseY, Space.Self);
        Camera.main.transform.Rotate(new Vector3(0f, mouseX * mouseSensitivity, 0f));

        Quaternion newRotation = Quaternion.Euler(-mouseY, mouseX, 0f);
        transform.rotation = originalRotation * newRotation;
    }
}
